targets.expr:
topk(
  10,
  sum by (topowner_kind,topowner_namespace,topowner_name) (
    rate(unifabric_port_rcv_data{cluster=~"$cluster", host_rdma!="true", pod_name!="", topowner_name!=""}[$__rate_interval])
  ) * 8
)

topk(
  10,
  sum by (topowner_kind,topowner_namespace,topowner_name) (
    rate(unifabric_port_xmit_data{cluster=~"$cluster", host_rdma!="true", pod_name!="", topowner_name!=""}[$__rate_interval])
  ) * 8
)

sum by (device,ifname, node_name) (
    rate(unifabric_np_cnp_sent{pod_name="", is_root="true", cluster=~"$cluster"}[$__rate_interval])
)

topk(10,
  sum by (pod_namespace, pod_name, device) (
    rate(unifabric_out_of_sequence{pod_name!="", cluster=~"$cluster"}[$__rate_interval])
  )
)
